// Paste a SMALL sample of video URLs/IDs to check (start small).
const videoUrls = ['REPLACE_WITH_VIDEO_URL_OR_ID_1', 'REPLACE_WITH_VIDEO_URL_OR_ID_2'];
return videoUrls.map((u) => ({ json: { videoUrl: u } }));

// One availability/status row per video. Credit-safe: failed/4xx/5xx/429 cost 0 credits;
// retry recommendation avoids re-running known-permanent failures (no_captions/invalid_id).
const out = [];
for (const item of $input.all()) {
  const d = item.json || {};
  if (Array.isArray(d.transcript) && d.transcript.length > 0) {
    out.push({ json: { videoId: d.video_id || null, status: 'available', errorReason: null, httpCode: 200, retryRecommendation: 'none', dedupeKey: d.video_id || null } });
  } else {
    const err = d.error || {};
    const code = err.httpCode || err.code || d.statusCode || null;
    let reason = 'unknown', retry = 'maybe';
    if (code == 404) { reason = 'no_captions'; retry = 'no'; }
    else if (code == 422) { reason = 'invalid_id'; retry = 'no'; }
    else if (code == 429) { reason = 'rate_limited_or_no_credits'; retry = 'later'; }
    else if (code && String(code).charAt(0) === '5') { reason = 'server_error'; retry = 'later'; }
    out.push({ json: { videoId: d.video_id || null, status: 'unavailable', errorReason: reason, httpCode: code, retryRecommendation: retry, dedupeKey: d.video_id || null } });
  }
}
return out;
